```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  (sqlgen::create_table<User> | sqlgen::if_not_exists)(conn);
  (sqlgen::create_table<Friendship> | sqlgen::if_not_exists)(conn);

  // Insert data
  conn->insert(users.begin(), users.end());
  conn->insert(friendships.begin(), friendships.end());

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = sqlgen::read<std::vector<FriendConnection>>
    | sqlgen::inner_join<User, "u1">("user_id"_t1 == "user_id"_t1)
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
    | sqlgen::where("user_id"_t1 < "user_id"_t2)
    | sqlgen::group_by("user_id"_t1, "user_id"_t2)
    | sqlgen::having(sqlgen::count() > 0);

  // Execute queries and return results
  auto mutual_friends_result = mutual_friends_query(conn);

  return mutual_friends_result.value();
}

}  // namespace analyze_social_network
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Creation**: Uses `sqlgen::create_table<T>` with `sqlgen::if_not_exists` to safely create tables

3. **Data Insertion**: Uses `conn->insert()` to populate the database with provided user and friendship data

4. **Mutual Friends Query**: Implements the SELF-JOIN query using sqlgen's fluent API:
   - Joins User table twice (aliased as u1 and u2)
   - Joins Friendship table twice (aliased as f1 and f2)
   - Uses WHERE clause to filter u1.user_id < u2.user_id
   - Groups by user IDs and filters with HAVING clause

5. **Return Type**: Returns `std::vector<FriendConnection>` containing mutual friend pairs

The implementation follows sqlgen best practices by using the fluent API with operator overloading (`|`) to build complex queries in a readable manner. The code handles error checking through the `Result` type returned by sqlgen operations.

